class Solution {
    public String largestWord(String word, int numFriends) {
        String max = "";
        for (int i = 1; i < word.length(); i++) {
            String first = word.substring(0, i);
            String second = word.substring(i);
            if (first.length() > 0 && second.length() > 0 && first.length() + second.length() == word.length()) {
                if (first.compareTo(max) > 0) {
                    max = first;
                }
                if (second.compareTo(max) > 0) {
                    max = second;
                }
            }
        }
        return max;
    }
    public String answerString(String word, int numFriends) {
        String res = word;
        for (int i = 0; i < word.length() - numFriends + 1; i++) {
            String s = word.substring(i, i + 1);
            if (s.compareTo(res) > 0) {
                res = s;
            }
        }
        for (int i = 0; i < word.length() - numFriends + 1; i++) {
            for (int j = i + 1; j < word.length() - numFriends + 2; j++) {
                String s = word.substring(i, j);
                if (s.compareTo(res) > 0) {
                    res = s;
                }
            }
        }
        return res;
    }
}

